/// swap_no_drain: s.status ≠ 0 ∨ s.yes_reserves > 0 ∨ s.no_reserves > 0
fn swap_no_drain(s: &State) -> bool {
    ((s.status != 0) || (s.yes_reserves > 0)) || (s.no_reserves > 0)
}

/// fee_bps_bounded: s.fee_bps ≤ 1000
fn fee_bps_bounded(s: &State) -> bool {
    s.fee_bps <= 1000
}

/// status_monotone: s.status ≤ 2
fn status_monotone(s: &State) -> bool {
    s.status <= 2
}

