fn initialize_pool(s: &mut State, subsidy_yes: u64, subsidy_no: u64, fee_bps: u64) -> bool {
    if !(s.initialized == 0 && subsidy_yes > 0 && subsidy_no > 0 && fee_bps <= 1000) {
        return false;
    }
    s.initialized = 1;
    s.status = 0;
    s.yes_reserves = subsidy_yes;
    s.no_reserves = subsidy_no;
    s.fee_bps = fee_bps;
    true
}

fn swap_yes_for_no(s: &mut State, amount_in: u64, amount_out: u64, min_amount_out: u64) -> bool {
    if !(s.status == 0 && amount_in > 0 && amount_out >= min_amount_out && amount_out < s.no_reserves) {
        return false;
    }
    match s.yes_reserves.checked_add(amount_in) {
        Some(__v) => s.yes_reserves = __v,
        None => return false,
    }
    match s.no_reserves.checked_sub(amount_out) {
        Some(__v) => s.no_reserves = __v,
        None => return false,
    }
    true
}

fn swap_no_for_yes(s: &mut State, amount_in: u64, amount_out: u64, min_amount_out: u64) -> bool {
    if !(s.status == 0 && amount_in > 0 && amount_out >= min_amount_out && amount_out < s.yes_reserves) {
        return false;
    }
    match s.no_reserves.checked_add(amount_in) {
        Some(__v) => s.no_reserves = __v,
        None => return false,
    }
    match s.yes_reserves.checked_sub(amount_out) {
        Some(__v) => s.yes_reserves = __v,
        None => return false,
    }
    true
}

fn mark_resolved_yes(s: &mut State) -> bool {
    if !(s.status == 0) {
        return false;
    }
    s.status = 1;
    true
}

fn mark_resolved_no(s: &mut State) -> bool {
    if !(s.status == 0) {
        return false;
    }
    s.status = 2;
    true
}

fn withdraw_yes_after_resolution(s: &mut State, amount: u64) -> bool {
    if !(s.status == 1 && amount > 0 && amount <= s.yes_reserves) {
        return false;
    }
    match s.yes_reserves.checked_sub(amount) {
        Some(__v) => s.yes_reserves = __v,
        None => return false,
    }
    true
}

fn withdraw_no_after_resolution(s: &mut State, amount: u64) -> bool {
    if !(s.status == 2 && amount > 0 && amount <= s.no_reserves) {
        return false;
    }
    match s.no_reserves.checked_sub(amount) {
        Some(__v) => s.no_reserves = __v,
        None => return false,
    }
    true
}

